def solve(graph, start, end):
    parents = {start: None}
    queue = [start]
    index = 0
    while index < len(queue):
        node = queue[index]
        index += 1
        if node == end:
            break
        for neighbor in graph.get(node, []):
            if neighbor not in parents:
                parents[neighbor] = node
                queue.append(neighbor)
    if end not in parents:
        return []
    path = []
    node = end
    while node is not None:
        path.append(node)
        node = parents[node]
    return path[::-1]

